import React, { Component } from 'react';

class FacebookFeed extends Component {

  componentDidMount() {
    window.FB.XFBML.parse();
  }

  render() {
    return (
      <div
        className="fb-page"
        data-href="https://www.facebook.com/trackandrally/"
        data-tabs="timeline"
        data-width="500"
        data-height=""
        data-small-header="false"
        data-adapt-container-width="true"
        data-hide-cover="false"
        data-show-facepile="false"
      >
        <blockquote
          cite="https://www.facebook.com/trackandrally/"
          className="fb-xfbml-parse-ignore"
        >
          If feed does not display, please try reloading the page.
          <a href="https://trackandrally.com/">Track and Rally</a>
        </blockquote>
      </div>
    )
  }
}

export default FacebookFeed;
